;,&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;吴签&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;罗志祥&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;pgOne&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;42&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                &lt;span class=&#34;token literal-property property&#34;&gt;user&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;span class=&#34;token literal-property property&#34;&gt;name&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;罗志祥&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token literal-property property&#34;&gt;hobby&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;时间管理&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token literal-property property&#34;&gt;age&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;33&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token literal-property property&#34;&gt;gender&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;男&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;43&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                &lt;span class=&#34;token literal-property property&#34;&gt;demo&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;44&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                    &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;span class=&#34;token literal-property property&#34;&gt;name&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;罗志祥&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token literal-property property&#34;&gt;hobby&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;时间管理&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token literal-property property&#34;&gt;age&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;33&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token literal-property property&#34;&gt;gender&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;男&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;45&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                    &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;span class=&#34;token literal-property property&#34;&gt;name&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;吴签&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token literal-property property&#34;&gt;hobby&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;踩缝纫机&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token literal-property property&#34;&gt;age&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;38&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token literal-property property&#34;&gt;gender&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;男&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;46&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                    &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;span class=&#34;token literal-property property&#34;&gt;name&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;pgOne&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token literal-property property&#34;&gt;hobby&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;理发&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token literal-property property&#34;&gt;age&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;23&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token literal-property property&#34;&gt;gender&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;男&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;47&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                    &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;span class=&#34;token literal-property property&#34;&gt;name&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;张三&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token literal-property property&#34;&gt;hobby&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;时间管理&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token literal-property property&#34;&gt;age&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;33&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token literal-property property&#34;&gt;gender&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;女&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;48&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                &lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;49&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;50&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;51&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;52&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;/&lt;/span&gt;script&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;53&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;/&lt;/span&gt;body&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;54&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;/&lt;/span&gt;html&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h5 id=&#34;5v-on-指令&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#5v-on-指令&#34;&gt;#&lt;/a&gt; 5.v-on 指令&lt;/h5&gt;
&lt;p&gt;v-on 指令用于事件的绑定。 当网页中的元素和事件绑定后， 触发事件可以执行事件函数， 完成一些操作。&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;!DOCTYPE html&amp;gt;
&amp;lt;html lang=&amp;quot;en&amp;quot;&amp;gt;
&amp;lt;head&amp;gt;
    &amp;lt;meta charset=&amp;quot;UTF-8&amp;quot;&amp;gt;
    &amp;lt;meta name=&amp;quot;viewport&amp;quot; content=&amp;quot;width=device-width, initial-scale=1.0&amp;quot;&amp;gt;
    &amp;lt;title&amp;gt;Document&amp;lt;/title&amp;gt;
    &amp;lt;script src=&amp;quot;../js/vue.js&amp;quot;&amp;gt;&amp;lt;/script&amp;gt;
&amp;lt;/head&amp;gt;
&amp;lt;body&amp;gt;
    &amp;lt;div id=&amp;quot;app&amp;quot;&amp;gt;
        &amp;lt;button v-on:click=&amp;quot;count++&amp;quot;&amp;gt;点我加1 === &amp;gt; &amp;#123;&amp;#123;count&amp;#125;&amp;#125;&amp;lt;/button&amp;gt;
        &amp;lt;button v-on:click=&amp;quot;fun&amp;quot;&amp;gt;点我加2 === &amp;gt; &amp;#123;&amp;#123;count&amp;#125;&amp;#125;&amp;lt;/button&amp;gt;
        &amp;lt;button @click=&amp;quot;fun1&amp;quot;&amp;gt;点我弹窗&amp;lt;/button&amp;gt;
        &amp;lt;button @click=&amp;quot;sum(12,34)&amp;quot;&amp;gt;两个数的和是:&amp;#123;&amp;#123;su&amp;#125;&amp;#125;&amp;lt;/button&amp;gt;

    &amp;lt;/div&amp;gt;

    &amp;lt;script&amp;gt;
        new Vue(&amp;#123;
            el:&amp;quot;#app&amp;quot;,
            data:&amp;#123;
                count:0,
                su:0
            &amp;#125;,
            methods: &amp;#123;
                fun()&amp;#123;
                    this.count+=2
                &amp;#125;,
                fun1()&amp;#123;
                    //js中的内置弹窗函数
                    alert(&amp;quot;我弹。。。&amp;quot;)
                &amp;#125;,
                sum(a,b)&amp;#123;
                    this.su = a + b
                &amp;#125;
            &amp;#125;
        &amp;#125;)
    &amp;lt;/script&amp;gt;
&amp;lt;/body&amp;gt;
&amp;lt;/html&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;h5 id=&#34;6v-bind-指令&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#6v-bind-指令&#34;&gt;#&lt;/a&gt; 6.v-bind 指令&lt;/h5&gt;
&lt;p&gt;v-bind 指令主要用于绑定元素的属性，当需要修改元素的属性值时，就需要使用 v-bind 的指令。&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;!DOCTYPE html&amp;gt;
&amp;lt;html lang=&amp;quot;en&amp;quot;&amp;gt;
&amp;lt;head&amp;gt;
    &amp;lt;meta charset=&amp;quot;UTF-8&amp;quot;&amp;gt;
    &amp;lt;meta name=&amp;quot;viewport&amp;quot; content=&amp;quot;width=device-width, initial-scale=1.0&amp;quot;&amp;gt;
    &amp;lt;title&amp;gt;Document&amp;lt;/title&amp;gt;
    &amp;lt;script src=&amp;quot;../js/vue.js&amp;quot;&amp;gt;&amp;lt;/script&amp;gt;
&amp;lt;/head&amp;gt;
&amp;lt;body&amp;gt;
    &amp;lt;div id=&amp;quot;app&amp;quot;&amp;gt;
        &amp;lt;!-- v-bind:herf绑定属性 --&amp;gt;
        &amp;lt;a v-bind:href=&amp;quot;hr&amp;quot;&amp;gt;点我跳转&amp;lt;/a&amp;gt;
        &amp;lt;button @click=&amp;quot;fun&amp;quot;&amp;gt;点我改变a 标签的地址&amp;lt;/button&amp;gt;
        &amp;lt;img :src=&amp;quot;im&amp;quot; alt=&amp;quot;&amp;quot; width=&amp;quot;400px&amp;quot;&amp;gt;
        &amp;lt;!-- 变量的拼接 --&amp;gt;
        &amp;lt;img :src=&amp;quot;&#39;../img/&#39; + address + &#39;.jpg&#39;&amp;quot; width=&amp;quot;100px&amp;quot; alt=&amp;quot;图片找不到2&amp;quot;&amp;gt;
        &amp;lt;!-- es6语法实现字符串与变量拼接 --&amp;gt;
        &amp;lt;img :src=&amp;quot;`../img/$&amp;#123;add&amp;#125;.jpg`&amp;quot; alt=&amp;quot;图片找不到3&amp;quot; width=&amp;quot;400px&amp;quot;&amp;gt;
    &amp;lt;/div&amp;gt;

    &amp;lt;script&amp;gt;
        new Vue(&amp;#123;
            el:&amp;quot;#app&amp;quot;,
            data:&amp;#123;
                hr:&amp;quot;first.html&amp;quot;,
                im:&amp;quot;../img/1.jpg&amp;quot;,
                address:2,
                add:3
            &amp;#125;,
            methods: &amp;#123;
                fun()&amp;#123;
                    this.hr = &amp;quot;https://www.bing.com&amp;quot;
                    this.im = &amp;quot;../img/2.jpg&amp;quot;
                &amp;#125;
            &amp;#125;,
        &amp;#125;)
    &amp;lt;/script&amp;gt;
&amp;lt;/body&amp;gt;
&amp;lt;/html&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;h5 id=&#34;7v-model-指令&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#7v-model-指令&#34;&gt;#&lt;/a&gt; 7.v-model 指令&lt;/h5&gt;
&lt;p&gt;v-model 指令主要用于 form 表单中的子元素实现双向数据绑定。 即可以通过视图改变 data 中的数据， 也可以通过 data 改变视图中显示的内容。&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;!DOCTYPE html&amp;gt;
&amp;lt;html lang=&amp;quot;en&amp;quot;&amp;gt;
&amp;lt;head&amp;gt;
    &amp;lt;meta charset=&amp;quot;UTF-8&amp;quot;&amp;gt;
    &amp;lt;meta name=&amp;quot;viewport&amp;quot; content=&amp;quot;width=device-width, initial-scale=1.0&amp;quot;&amp;gt;
    &amp;lt;title&amp;gt;Document&amp;lt;/title&amp;gt;

&amp;lt;/head&amp;gt;
&amp;lt;body&amp;gt;
    &amp;lt;div id=&amp;quot;app&amp;quot;&amp;gt;
        &amp;#123;&amp;#123;name&amp;#125;&amp;#125; : &amp;lt;input type=&amp;quot;text&amp;quot; v-model=&amp;quot;name&amp;quot;&amp;gt;
        修改性别:
        &amp;lt;input type=&amp;quot;text&amp;quot; v-model=&amp;quot;sex&amp;quot;&amp;gt;
        性别:
        &amp;lt;input type=&amp;quot;radio&amp;quot; name=&amp;quot;gender&amp;quot; v-model=&amp;quot;sex&amp;quot; value=&amp;quot;男&amp;quot;&amp;gt;男
        &amp;lt;input type=&amp;quot;radio&amp;quot; name=&amp;quot;gender&amp;quot; v-model=&amp;quot;sex&amp;quot; value=&amp;quot;女&amp;quot;&amp;gt;女&amp;lt;br&amp;gt;
        爱好:
        &amp;lt;input type=&amp;quot;checkbox&amp;quot; name=&amp;quot;hobby&amp;quot; v-model=&amp;quot;hob&amp;quot; value=&amp;quot;唱&amp;quot;&amp;gt;唱
        &amp;lt;input type=&amp;quot;checkbox&amp;quot; name=&amp;quot;hobby&amp;quot; v-model=&amp;quot;hob&amp;quot; value=&amp;quot;跳&amp;quot;&amp;gt;跳
        &amp;lt;input type=&amp;quot;checkbox&amp;quot; name=&amp;quot;hobby&amp;quot; v-model=&amp;quot;hob&amp;quot; value=&amp;quot;rap&amp;quot;&amp;gt;rap
        &amp;lt;input type=&amp;quot;checkbox&amp;quot; name=&amp;quot;hobby&amp;quot; v-model=&amp;quot;hob&amp;quot; value=&amp;quot;篮球&amp;quot;&amp;gt;篮球
        &amp;lt;input type=&amp;quot;checkbox&amp;quot; name=&amp;quot;hobby&amp;quot; v-model=&amp;quot;hob&amp;quot; value=&amp;quot;music&amp;quot;&amp;gt;music&amp;lt;br&amp;gt;
        &amp;lt;p&amp;gt;&amp;#123;&amp;#123;hob&amp;#125;&amp;#125;&amp;lt;/p&amp;gt;

    &amp;lt;/div&amp;gt;
    &amp;lt;script src=&amp;quot;../js/vue.js&amp;quot;&amp;gt;&amp;lt;/script&amp;gt;
    &amp;lt;script&amp;gt;
        new Vue(&amp;#123;
            el:&amp;quot;#app&amp;quot;,
            data:&amp;#123;
                name:&amp;quot;疯不觉&amp;quot;,
                sex:&amp;quot;男&amp;quot;,
                hob:[&amp;quot;唱&amp;quot;,&amp;quot;跳&amp;quot;]
            &amp;#125;,

        &amp;#125;)
    &amp;lt;/script&amp;gt;
&amp;lt;/body&amp;gt;
&amp;lt;/html&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;h4 id=&#34;6计算属性&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#6计算属性&#34;&gt;#&lt;/a&gt; 6. 计算属性&lt;/h4&gt;
&lt;p&gt;Vue 中有一个 computed，通过这个 computed 可以完成一个复杂的计算.computed 这个是 vue 的计算属性。存在的意义是为了使得视图中需要运算才会得到结果的数据更加美观。&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;!DOCTYPE html&amp;gt;
&amp;lt;html lang=&amp;quot;en&amp;quot;&amp;gt;
&amp;lt;head&amp;gt;
    &amp;lt;meta charset=&amp;quot;UTF-8&amp;quot;&amp;gt;
    &amp;lt;meta name=&amp;quot;viewport&amp;quot; content=&amp;quot;width=device-width, initial-scale=1.0&amp;quot;&amp;gt;
    &amp;lt;title&amp;gt;Document&amp;lt;/title&amp;gt;
    &amp;lt;script src=&amp;quot;../js/vue.js&amp;quot;&amp;gt;&amp;lt;/script&amp;gt;
&amp;lt;/head&amp;gt;
&amp;lt;body&amp;gt;
    &amp;lt;div id=&amp;quot;app&amp;quot;&amp;gt;
        &amp;lt;!-- 获取当前系统时间以**年**月**日的格式显示 --&amp;gt;
        &amp;lt;h2&amp;gt;&amp;#123;&amp;#123;new Date().getFullYear()&amp;#125;&amp;#125; 年 &amp;#123;&amp;#123;new Date().getFullMonth()&amp;#125;&amp;#125; 月 &amp;#123;&amp;#123;new Date().getFullDay()&amp;#125;&amp;#125; 日 &amp;lt;/h2&amp;gt;
        &amp;lt;!-- 计算属性来计算时间并格式化 --&amp;gt;
        &amp;lt;h3&amp;gt;&amp;#123;&amp;#123;formatdate&amp;#125;&amp;#125;&amp;lt;/h3&amp;gt;
    &amp;lt;/div&amp;gt;


    &amp;lt;script&amp;gt;
        new Vue(&amp;#123;
            el:&amp;quot;#app&amp;quot;,
            data:&amp;#123;

            &amp;#125;,
            computed:&amp;#123;
                formatdate()&amp;#123;
                    return `$&amp;#123;new Date().getFullYear()&amp;#125; 年 $&amp;#123;new Date().getFullMonth()&amp;#125; 月 $&amp;#123;new Date().getFullDay()&amp;#125;日`
                &amp;#125;
            &amp;#125;
        &amp;#125;)
    &amp;lt;/script&amp;gt;
&amp;lt;/body&amp;gt;
&amp;lt;/html&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;h4 id=&#34;7监听属性&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#7监听属性&#34;&gt;#&lt;/a&gt; 7. 监听属性&lt;/h4&gt;
&lt;p&gt;Vue 里面还有 watch 属性，这个 watch 属性是监听属性。监控一个值的变化，从而做出相应的反应。&lt;/p&gt;
&lt;p&gt;可以监听属性的变化从而获取变化前的旧值和变化后的新值。&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;!DOCTYPE html&amp;gt;
&amp;lt;html lang=&amp;quot;en&amp;quot;&amp;gt;
&amp;lt;head&amp;gt;
    &amp;lt;meta charset=&amp;quot;UTF-8&amp;quot;&amp;gt;
    &amp;lt;meta name=&amp;quot;viewport&amp;quot; content=&amp;quot;width=device-width, initial-scale=1.0&amp;quot;&amp;gt;
    &amp;lt;title&amp;gt;Document&amp;lt;/title&amp;gt;
    &amp;lt;script src=&amp;quot;../js/vue.js&amp;quot;&amp;gt;&amp;lt;/script&amp;gt;
&amp;lt;/head&amp;gt;
&amp;lt;body&amp;gt;
    &amp;lt;div id=&amp;quot;app&amp;quot;&amp;gt;
        &amp;#123;&amp;#123;na&amp;#125;&amp;#125; : &amp;lt;input type=&amp;quot;text&amp;quot; v-model=&amp;quot;na&amp;quot;&amp;gt;
    &amp;lt;/div&amp;gt;

    &amp;lt;script&amp;gt;
        new Vue(&amp;#123;
            el:&amp;quot;#app&amp;quot;,
            data:&amp;#123;
                na:&#39;&#39;,
                bb:&#39;&#39;
            &amp;#125;,
            watch:&amp;#123;
                na(newvalue,oldvalue)&amp;#123;
                    console.log(newvalue,oldvalue)
                &amp;#125;
            &amp;#125;
        &amp;#125;)
    &amp;lt;/script&amp;gt;
&amp;lt;/body&amp;gt;
&amp;lt;/html&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;h4 id=&#34;8vue-的生命周期&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#8vue-的生命周期&#34;&gt;#&lt;/a&gt; 8.Vue 的生命周期&lt;/h4&gt;
&lt;p&gt;Vue 的生命周期从 Vue 实例初始化创建、 模板的挂载、 以及数据的修改和销毁整个过程共计四个大阶 段， 每个阶段都有两个钩子函数。 在执行到对应阶段时， 钩子函数会自动被调用。 用户可以在对应的 钩子函数中完成相应的操作。 从初始化到销毁的过程就是 Vue 的生命周期。&lt;/p&gt;
&lt;p&gt;对应钩子函数介绍：&lt;/p&gt;
&lt;p&gt;beforeCreate: 在 Vue 实例初始化之后，数据和事件配置之前被调用.&lt;/p&gt;
&lt;p&gt;created: 在实例创建完成后被立即同步调用。在这一步中，实例已完成对选项的处理，意味着以下内容 已被配置完毕：数据侦听、计算属性、方法、事件 / 侦听器的回调函数。然而，挂载阶段还没开始。&lt;/p&gt;
&lt;p&gt;beforeMount: 在挂载前被调用，render 函数被调用，生成虚拟的 dom, 真实 dom 未创建.&lt;/p&gt;
&lt;p&gt;mounted: 挂载完成。真实 dom 树已经完成，渲染到页面。可以进行 dom 操作。&lt;/p&gt;
&lt;p&gt;beforeUpdate：在数据发生改变后，DOM 被更新之前被调用。这里适合在现有 DOM 将要被更新之前访问 它，比如移除手动添加的事件监听器。&lt;/p&gt;
&lt;p&gt;updated: 在数据更改导致的虚拟 DOM 重新渲染和更新完毕之后被调用。&lt;/p&gt;
&lt;p&gt;beforeDestroy：实例销毁之前调用。在这一步，实例仍然完全可用。&lt;/p&gt;
&lt;p&gt;destroyed: 实例销毁后调用。该钩子被调用后，对应 Vue 实例的所有指令都被解绑，所有的事件监听器被移除，所有的子实例也都被销毁。&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;&amp;lt;!DOCTYPE html&amp;gt;
&amp;lt;html lang=&amp;quot;en&amp;quot;&amp;gt;
&amp;lt;head&amp;gt;
    &amp;lt;meta charset=&amp;quot;UTF-8&amp;quot;&amp;gt;
    &amp;lt;meta name=&amp;quot;viewport&amp;quot; content=&amp;quot;width=device-width, initial-scale=1.0&amp;quot;&amp;gt;
    &amp;lt;title&amp;gt;Document&amp;lt;/title&amp;gt;
    &amp;lt;script src = &amp;quot;../js/vue.js&amp;quot;&amp;gt;&amp;lt;/script&amp;gt;
&amp;lt;/head&amp;gt;
&amp;lt;body&amp;gt;
    &amp;lt;div id=&amp;quot;app&amp;quot;&amp;gt;
        &amp;lt;input type=&amp;quot;text&amp;quot; v-model=&amp;quot;info&amp;quot;&amp;gt;&amp;lt;br&amp;gt;
    &amp;lt;/div&amp;gt;

    &amp;lt;script&amp;gt;
        new Vue(&amp;#123;
            el:&amp;quot;#app&amp;quot;,
            data:&amp;#123;
                info:&#39;victory&#39;
            &amp;#125;,
            beforeCreate() &amp;#123;
                console.log(&amp;quot;vue实例初始化前&amp;quot; + this.info)
            &amp;#125;,
            created() &amp;#123;
                console.log(&amp;quot;vue实例初始化完成&amp;quot; + this.info)
            &amp;#125;,
            beforeMount() &amp;#123;
                console.log(&amp;quot;vue视图挂载之前&amp;quot; + this.info)
            &amp;#125;,
            mounted() &amp;#123;
                console.log(&amp;quot;vue视图挂载完成&amp;quot; + this.info)
            &amp;#125;,
            beforeUpdate() &amp;#123;
                console.log(&amp;quot;vue中的内容被修改前触发&amp;quot; + this.info)
            &amp;#125;,
            updated() &amp;#123;
                console.log(&amp;quot;vue中的内容被修改后触发&amp;quot; + this.info) 
            &amp;#125;,
            beforeDestroy() &amp;#123;
                console.log(&amp;quot;vue实例被销毁前触发&amp;quot; + this.info) 
            &amp;#125;,
            destroyed() &amp;#123;
                console.log(&amp;quot;vue实例被销毁&amp;quot; + this.info) 
            &amp;#125;,
        &amp;#125;)
    &amp;lt;/script&amp;gt;
&amp;lt;/body&amp;gt;
&amp;lt;/html&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;day7-vue和elementui&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#day7-vue和elementui&#34;&gt;#&lt;/a&gt; Day7 Vue 和 ElementUI&lt;/h2&gt;
&lt;h3 id=&#34;1-vue的组件&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1-vue的组件&#34;&gt;#&lt;/a&gt; 1. Vue 的组件&lt;/h3&gt;
&lt;p&gt;组件系统是 Vue 的另一个重要概念，因为它是一种抽象，允许我们使用小型、独立和通常可复用的组件构建大型应用。仔细想想，几乎任意类型的应用界面都可以抽象为一个组件树， 主要作用，实现模块化开发， 实现组件的复用。 Vue 中的组件组要有两种存在形式，一种是全局组件， 一种是局部组件。&lt;/p&gt;
&lt;h4 id=&#34;11-全局组件&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#11-全局组件&#34;&gt;#&lt;/a&gt; 1.1 全局组件&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;全局组件在定义好之后可以在任何一个 Vue 实例对应的视图中去使用， 不需要单独注册。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;语法：  &lt;code&gt;Vue.component(&amp;quot;组件名&amp;quot;,&amp;#123;template: &#39;模板视图&#39;, data()&amp;#123;return &amp;#123;&amp;#125;&amp;#125;,methods:&amp;#123;&amp;#125;&amp;#125;)&lt;/code&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;实例：&lt;/p&gt;
&lt;figure class=&#34;highlight html&#34;&gt;&lt;figcaption data-lang=&#34;HTML&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token doctype&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;!&lt;/span&gt;&lt;span class=&#34;token doctype-tag&#34;&gt;DOCTYPE&lt;/span&gt; &lt;span class=&#34;token name&#34;&gt;html&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;html&lt;/span&gt; &lt;span class=&#34;token attr-name&#34;&gt;lang&lt;/span&gt;&lt;span class=&#34;token attr-value&#34;&gt;&lt;span class=&#34;token punctuation attr-equals&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;en&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;head&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;meta&lt;/span&gt; &lt;span class=&#34;token attr-name&#34;&gt;charset&lt;/span&gt;&lt;span class=&#34;token attr-value&#34;&gt;&lt;span class=&#34;token punctuation attr-equals&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;UTF-8&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;meta&lt;/span&gt; &lt;span class=&#34;token attr-name&#34;&gt;name&lt;/span&gt;&lt;span class=&#34;token attr-value&#34;&gt;&lt;span class=&#34;token punctuation attr-equals&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;viewport&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;&lt;/span&gt; &lt;span class=&#34;token attr-name&#34;&gt;content&lt;/span&gt;&lt;span class=&#34;token attr-value&#34;&gt;&lt;span class=&#34;token punctuation attr-equals&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;width=device-width, initial-scale=1.0&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;title&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;Document&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;/&lt;/span&gt;title&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;/&lt;/span&gt;head&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;body&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;div&lt;/span&gt; &lt;span class=&#34;token attr-name&#34;&gt;id&lt;/span&gt;&lt;span class=&#34;token attr-value&#34;&gt;&lt;span class=&#34;token punctuation attr-equals&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;app&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;h1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;第一个视图&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;/&lt;/span&gt;h1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp