            &amp;#125;,&amp;#123;
              value: &#39;chendu&#39;,
              label: &#39;成都&#39;
            &amp;#125;
            ]
          &amp;#125;, 
          &amp;#123;
            label: &#39;城市名&#39;,
            options: [&amp;#123;
              value: &#39;Chengdu&#39;,
              label: &#39;成都&#39;
            &amp;#125;, &amp;#123;
