            children: [&amp;#123;
              value: &#39;one&#39;,
              label: &#39;一区&#39;
            &amp;#125;, &amp;#123;
              value: &#39;two&#39;,
              label: &#39;二区&#39;
            &amp;#125;]
          &amp;#125;]
        &amp;#125;, 
        &amp;#123;
          value: &#39;2&#39;,
          label: &#39;甘肃&#39;,
          children: [&amp;#123;
            value: &#39;lanzou&#39;,
            label: &#39;兰州&#39;,
            children: [&amp;#123;
              value: &#39;gaoxin&#39;,
              label: &#39;高新&#39;
            &amp;#125;, &amp;#123;
              value: &#39;aa&#39;,
              label: &#39;A区&#39;
            &amp;#125;]
          &amp;#125;, &amp;#123;
            value: &#39;qinyang&#39;,
            label: &#39;庆阳&#39;,
            children: [&amp;#123;
              value: &#39;qinyang1&#39;,
              label: &#39;庆阳1区&#39;
            &amp;#125;, &amp;#123;
              value: &#39;qinyang2&#39;,
              label: &#39;庆阳3区&#39;
            &amp;#125;, &amp;#123;
              value: &#39;qinyang3&#39;,
