            &amp;#125;]
          &amp;#125;, &amp;#123;
            value: &#39;data&#39;,
            label: &#39;Data&#39;,
            children: [&amp;#123;
              value: &#39;table&#39;,
              label: &#39;Table 表格&#39;
            &amp;#125;, &amp;#123;
              value: &#39;tag&#39;,
              label: &#39;Tag 标签&#39;
            &amp;#125;, &amp;#123;
              value: &#39;progress&#39;,
