            &amp;#125;, &amp;#123;
              value: &#39;tree&#39;,
              label: &#39;Tree 树形控件&#39;
            &amp;#125;, &amp;#123;
              value: &#39;pagination&#39;,
              label: &#39;Pagination 分页&#39;
            &amp;#125;, &amp;#123;
              value: &#39;badge&#39;,
              label: &#39;Badge 标记&#39;
            &amp;#125;]
          &amp;#125;,]
        &amp;#125;, 
        &amp;#123;
          value: &#39;3&#39;,
          label: &#39;陕西&#39;,
          children: [&amp;#123;
            value: &#39;hanzhong&#39;,
