&lt;h3 id=&#34;6timepicker-时间选择器&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#6timepicker-时间选择器&#34;&gt;#&lt;/a&gt; 6.TimePicker 时间选择器&lt;/h3&gt;
&lt;p&gt;用于选择或输入时间&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-vue&#34;&gt;&amp;lt;template&amp;gt;
    &amp;lt;div&amp;gt;
        &amp;lt;!-- :picker-options=&amp;quot;&amp;#123;
            selectableRange: &#39;18:30:00 - 20:30:00&#39;
        &amp;#125;&amp;quot; 设置可选择事件范围 --&amp;gt;
        &amp;lt;el-time-picker
        v-model=&amp;quot;value1&amp;quot;
        :picker-options=&amp;quot;&amp;#123;
            selectableRange: &#39;18:30:00 - 20:30:00&#39;
        &amp;#125;&amp;quot;
        placeholder=&amp;quot;任意时间点&amp;quot;&amp;gt;
        &amp;lt;/el-time-picker&amp;gt;

        &amp;lt;el-time-picker
        arrow-control
        v-model=&amp;quot;value2&amp;quot;

        :picker-options=&amp;quot;&amp;#123;
            selectableRange: &#39;18:30:00 - 20:30:00&#39;
        &amp;#125;&amp;quot;
        placeholder=&amp;quot;任意时间点&amp;quot;&amp;gt;
        &amp;lt;/el-time-picker&amp;gt;
    &amp;lt;/div&amp;gt;
  &amp;lt;/template&amp;gt;

  &amp;lt;script&amp;gt;
    export default &amp;#123;
      data() &amp;#123;
        return &amp;#123;
          value1: new Date(2016, 9, 10, 18, 40),
          value2: new Date(2023, 10, 10, 23 , 40)
        &amp;#125;;
      &amp;#125;
    &amp;#125;
  &amp;lt;/script&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;h3 id=&#34;7选择日期范围&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#7选择日期范围&#34;&gt;#&lt;/a&gt; 7. 选择日期范围&lt;/h3&gt;
&lt;p&gt;可在一个选择器中便捷地选择一个时间范围&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-vue&#34;&gt;&amp;lt;template&amp;gt;
    &amp;lt;div class=&amp;quot;block&amp;quot;&amp;gt;
    &amp;lt;span class=&amp;quot;demonstration&amp;quot;&amp;gt;带快捷选项&amp;lt;/span&amp;gt;
    &amp;lt;el-date-picker
      v-model=&amp;quot;value2&amp;quot;
      type=&amp;quot;monthrange&amp;quot;
      align=&amp;quot;right&amp;quot;
      unlink-panels
      range-separator=&amp;quot;至&amp;quot;
      start-placeholder=&amp;quot;开始月份&amp;quot;
      end-placeholder=&amp;quot;结束月份&amp;quot;
      :picker-options=&amp;quot;pickerOptions&amp;quot;&amp;gt;
    &amp;lt;/el-date-picker&amp;gt;
  &amp;lt;/div&amp;gt;
&amp;lt;/template&amp;gt;

&amp;lt;script&amp;gt;
  export default &amp;#123;
    data() &amp;#123;
      return &amp;#123;
        pickerOptions: &amp;#123;
          shortcuts: [&amp;#123;
            text: &#39;本月&#39;,
            onClick(picker) &amp;#123;
              picker.$emit(&#39;pick&#39;, [new Date(), new Date()]);
            &amp;#125;
          &amp;#125;, &amp;#123;
            text: &#39;今年至今&#39;,
            onClick(picker) &amp;#123;
              const end = new Date();
              const start = new Date(new Date().getFullYear(), 0);
              picker.$emit(&#39;pick&#39;, [start, end]);
            &amp;#125;
          &amp;#125;, &amp;#123;
            text: &#39;最近六个月&#39;,
            onClick(picker) &amp;#123;
              const end = new Date();
              const start = new Date();
              start.setMonth(start.getMonth() - 6);
              picker.$emit(&#39;pick&#39;, [start, end]);
            &amp;#125;
          &amp;#125;]
        &amp;#125;,
        value2: &#39;&#39;
      &amp;#125;;
    &amp;#125;
  &amp;#125;;
&amp;lt;/script&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;h3 id=&#34;8-upload-上传&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#8-upload-上传&#34;&gt;#&lt;/a&gt; 8. Upload 上传&lt;/h3&gt;
&lt;p&gt;通过点击或者拖拽上传文件&lt;/p&gt;
&lt;h4 id=&#34;文件缩略图&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#文件缩略图&#34;&gt;#&lt;/a&gt; 文件缩略图&lt;/h4&gt;
&lt;p&gt;使用  &lt;code&gt;scoped-slot&lt;/code&gt;  去设置缩略图模版。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-vue&#34;&gt;&amp;lt;template&amp;gt;
    &amp;lt;div&amp;gt;
        &amp;lt;!--action上传服务器的地址 :auto-upload=&amp;quot;false&amp;quot;是否自动上传， 如果设置自动上传， 需要给action 一个值  
        handlePictureCardPreview 鼠标在图片上的预览效果
        handleDownload(file) 点击下载的按钮触发的事件
        @click=&amp;quot;handleRemove(file)&amp;quot; 点击删除触发的事件函数

        --&amp;gt;
        &amp;lt;el-upload
        action=&amp;quot;#&amp;quot;
        list-type=&amp;quot;picture-card&amp;quot;
        :auto-upload=&amp;quot;false&amp;quot;&amp;gt;
            &amp;lt;i slot=&amp;quot;default&amp;quot; class=&amp;quot;el-icon-plus&amp;quot;&amp;gt;&amp;lt;/i&amp;gt;
            &amp;lt;div slot=&amp;quot;file&amp;quot; slot-scope=&amp;quot;&amp;#123;file&amp;#125;&amp;quot;&amp;gt;
            &amp;lt;img
                class=&amp;quot;el-upload-list__item-thumbnail&amp;quot;
                :src=&amp;quot;file.url&amp;quot; alt=&amp;quot;&amp;quot;
            &amp;gt;
            &amp;lt;span class=&amp;quot;el-upload-list__item-actions&amp;quot;&amp;gt;
                &amp;lt;span
                class=&amp;quot;el-upload-list__item-preview&amp;quot;
                @click=&amp;quot;handlePictureCardPreview(file)&amp;quot;
                &amp;gt;
                &amp;lt;i class=&amp;quot;el-icon-zoom-in&amp;quot;&amp;gt;&amp;lt;/i&amp;gt;
                &amp;lt;/span&amp;gt;
                &amp;lt;span
                v-if=&amp;quot;!disabled&amp;quot;
                class=&amp;quot;el-upload-list__item-delete&amp;quot;
                @click=&amp;quot;handleDownload(file)&amp;quot;
                &amp;gt;
                &amp;lt;i class=&amp;quot;el-icon-download&amp;quot;&amp;gt;&amp;lt;/i&amp;gt;
                &amp;lt;/span&amp;gt;
                &amp;lt;span
                v-if=&amp;quot;!disabled&amp;quot;
                class=&amp;quot;el-upload-list__item-delete&amp;quot;
                @click=&amp;quot;handleRemove(file)&amp;quot;
                &amp;gt;
                &amp;lt;i class=&amp;quot;el-icon-delete&amp;quot;&amp;gt;&amp;lt;/i&amp;gt;
                &amp;lt;/span&amp;gt;
            &amp;lt;/span&amp;gt;
            &amp;lt;/div&amp;gt;
        &amp;lt;/el-upload&amp;gt;
        &amp;lt;!-- 上传的图片回显位置  :src=&amp;quot;dialogImageUrl&amp;quot; 回显图片的地址值--&amp;gt;
        &amp;lt;el-dialog :visible.sync=&amp;quot;dialogVisible&amp;quot;&amp;gt;
        &amp;lt;img width=&amp;quot;100%&amp;quot; :src=&amp;quot;dialogImageUrl&amp;quot; alt=&amp;quot;&amp;quot;&amp;gt;
        &amp;lt;/el-dialog&amp;gt;
    &amp;lt;/div&amp;gt;
&amp;lt;/template&amp;gt;

&amp;lt;script&amp;gt;
  export default &amp;#123;
    data() &amp;#123;
      return &amp;#123;
        dialogImageUrl: &#39;&#39;,
        dialogVisible: false,
        disabled: false
      &amp;#125;;
    &amp;#125;,
    methods: &amp;#123;
      handleRemove(file) &amp;#123;
        console.log(file);
      &amp;#125;,
      handlePictureCardPreview(file) &amp;#123;
        this.dialogImageUrl = file.url;
        this.dialogVisible = true;
      &amp;#125;,
      handleDownload(file) &amp;#123;
        console.log(file);
      &amp;#125;
    &amp;#125;
  &amp;#125;
&amp;lt;/script&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;h3 id=&#34;9-rate-评分和穿梭&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#9-rate-评分和穿梭&#34;&gt;#&lt;/a&gt; 9. Rate 评分和穿梭&lt;/h3&gt;
&lt;p&gt;评分组件&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-vue&#34;&gt;&amp;lt;template&amp;gt;
    &amp;lt;div&amp;gt;
        &amp;lt;div&amp;gt;
            &amp;lt;el-rate
                v-model=&amp;quot;value1&amp;quot;
                show-text&amp;gt;
            &amp;lt;/el-rate&amp;gt;
        &amp;lt;/div&amp;gt;
        &amp;lt;hr&amp;gt;
        &amp;lt;div&amp;gt;
            &amp;lt;el-rate
            v-model=&amp;quot;value2&amp;quot;
            :icon-classes=&amp;quot;iconClasses&amp;quot;
            void-icon-class=&amp;quot;el-icon-sunny&amp;quot;
            :colors=&amp;quot;[&#39;#99A9BF&#39;, &#39;#F7BA2A&#39;, &#39;#FF9900&#39;]&amp;quot;&amp;gt;
            &amp;lt;/el-rate&amp;gt;
        &amp;lt;/div&amp;gt;

        &amp;lt;div class=&amp;quot;block&amp;quot;&amp;gt;
        &amp;lt;span class=&amp;quot;demonstration&amp;quot;&amp;gt;默认不区分颜色&amp;lt;/span&amp;gt;
        &amp;lt;el-rate v-model=&amp;quot;value1&amp;quot;&amp;gt;&amp;lt;/el-rate&amp;gt;
        &amp;lt;/div&amp;gt;


        &amp;lt;div&amp;gt;
            &amp;lt;el-transfer v-model=&amp;quot;value&amp;quot; :data=&amp;quot;data&amp;quot;&amp;gt;&amp;lt;/el-transfer&amp;gt;
        &amp;lt;/div&amp;gt;

    &amp;lt;/div&amp;gt;


&amp;lt;/template&amp;gt;

&amp;lt;script&amp;gt;
  export default &amp;#123;
    data() &amp;#123;
        /* const generateData = ()=&amp;gt; &amp;#123;
        const data = [
            &amp;#123;
                key: 1,
                label: &amp;quot;张三&amp;quot;
            &amp;#125;,
            &amp;#123;
                key: 2,
                label: &amp;quot;张是&amp;quot;
            &amp;#125;,
            &amp;#123;
                key: 2,
                label: &amp;quot;张5&amp;quot;
            &amp;#125;,
    ];
        /* for (let i = 1; i &amp;lt;= 15; i++) &amp;#123;
          data.push(&amp;#123;
            key: i,
            label: `备选项 $&amp;#123; i &amp;#125;`,
            disabled: i % 4 === 0
          &amp;#125;);
        &amp;#125; 
        return data;
      &amp;#125;; */

      return &amp;#123;
        data: [
            &amp;#123;
                key: 1,
                label: &amp;quot;张三&amp;quot;
            &amp;#125;,
            &amp;#123;
                key: 2,
                label: &amp;quot;张是&amp;quot;
            &amp;#125;,
            &amp;#123;
                key: 2,
                label: &amp;quot;张5&amp;quot;
            &amp;#125;,
        ],
        value: [1, 4],
        value1: null,
        value2: null,
        iconClasses: [&#39;el-icon-eleme&#39;, &#39;el-icon-eleme&#39;, &#39;el-icon-eleme&#39;] 
      &amp;#125;;

    &amp;#125;
  &amp;#125;
&amp;lt;/script&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;h3 id=&#34;10-form-表单&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#10-form-表单&#34;&gt;#&lt;/a&gt; 10. Form 表单&lt;/h3&gt;
&lt;p&gt;由输入框、选择器、单选框、多选框等控件组成，用以收集、校验、提交数据&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-vue&#34;&gt;&amp;lt;template&amp;gt;
    &amp;lt;div&amp;gt;
        &amp;lt;!-- :model=&amp;quot;ruleForm&amp;quot; 表单中所有数据  --&amp;gt;
        &amp;lt;el-row&amp;gt;
            &amp;lt;el-col :span=&amp;quot;8&amp;quot; :offset=&amp;quot;8&amp;quot;&amp;gt;
                &amp;lt;el-form :model=&amp;quot;ruleForm&amp;quot; :rules=&amp;quot;rules&amp;quot; ref=&amp;quot;ruleForm1&amp;quot; label-width=&amp;quot;100px&amp;quot; class=&amp;quot;demo-ruleForm&amp;quot;&amp;gt;

                &amp;lt;el-form-item label=&amp;quot;用户名&amp;quot; prop=&amp;quot;name&amp;quot;&amp;gt;
                    &amp;lt;el-input v-model=&amp;quot;ruleForm.name&amp;quot;&amp;gt;&amp;lt;/el-input&amp;gt;
                &amp;lt;/el-form-item&amp;gt;

                &amp;lt;el-form-item label=&amp;quot;电话号码&amp;quot; prop=&amp;quot;phone&amp;quot;&amp;gt;
                    &amp;lt;el-input v-model=&amp;quot;ruleForm.phone&amp;quot;&amp;gt;&amp;lt;/el-input&amp;gt;
                &amp;lt;/el-form-item&amp;gt;
                &amp;lt;el-form-item label=&amp;quot;密码&amp;quot; prop=&amp;quot;password&amp;quot;&amp;gt;
                    &amp;lt;el-input v-model=&amp;quot;ruleForm.password&amp;quot;&amp;gt;&amp;lt;/el-input&amp;gt;
                &amp;lt;/el-form-item&amp;gt;

                &amp;lt;el-form-item&amp;gt;
                    &amp;lt;el-button type=&amp;quot;primary&amp;quot; @click=&amp;quot;submitForm(&#39;ruleForm1&#39;)&amp;quot;&amp;gt;立即创建&amp;lt;/el-button&amp;gt;
                    &amp;lt;el-button @click=&amp;quot;resetForm(&#39;ruleForm&#39;)&amp;quot;&amp;gt;重置&amp;lt;/el-button&amp;gt;
                &amp;lt;/el-form-item&amp;gt;
                &amp;lt;/el-form&amp;gt;
            &amp;lt;/el-col&amp;gt;
        &amp;lt;/el-row&amp;gt;

    &amp;lt;/div&amp;gt;
&amp;lt;/template&amp;gt;

&amp;lt;script&amp;gt;
  export default &amp;#123;
    data() &amp;#123;
      return &amp;#123;
        ruleForm: &amp;#123;
          name: &#39;&#39;,
          password: &#39;&#39;,
          phone:&#39;&#39;

        &amp;#125;,
        // 表单验证规则的设置位置
        rules: &amp;#123;
		// 自定义表单验证规则
          phone:[
            &amp;#123;validator: 

                (rule,value,callback) =&amp;gt;&amp;#123;
                    if (value === &#39;&#39;) &amp;#123;
                        callback(new Error(&#39;请输入电话号码&#39;));
                    &amp;#125; else &amp;#123;
                        let regx = /^1[3456789][0-9]&amp;#123;9&amp;#125;$/;
                        if (!regx.test(value)) &amp;#123;
                            callback(new Error(&#39;电话号码必须符合规范&#39;));
                        &amp;#125;
                        callback();
                    &amp;#125;
            &amp;#125;,
            trigger: &#39;blur&#39;&amp;#125;
          ],
          name: [
            &amp;#123; required: true, message: &#39;请输入用户名称&#39;, trigger: &#39;blur&#39; &amp;#125;,
            &amp;#123; min: 3, max: 5, message: &#39;长度在 3 到 5 个字符&#39;, trigger: &#39;blur&#39; &amp;#125;
          ],
          password: [
            &amp;#123; required: true, message: &#39;请输入密码&#39;, trigger: &#39;blur&#39; &amp;#125;
          ]
        &amp;#125;
      &amp;#125;;
    &amp;#125;,
    methods: &amp;#123;
        // 表单提交的函数
      submitForm(formName) &amp;#123;
        this.$refs[formName].validate((valid) =&amp;gt; &amp;#123;
          if (valid) &amp;#123;
            alert(&#39;登陆成功~~&#39;);
          &amp;#125; else &amp;#123;
            console.log(&#39;error submit!!&#39;);
            return false;
          &amp;#125;
        &amp;#125;);
      &amp;#125;,
      // 表单重置的函数
      resetForm() &amp;#123;
        // this.$refs[formName].resetFields();
        this.ruleForm = &amp;#123;&amp;#125;
      &amp;#125;
    &amp;#125;
  &amp;#125;
&amp;lt;/script&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;h3 id=&#34;11-table-表格&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#11-table-表格&#34;&gt;#&lt;/a&gt; 11. Table 表格&lt;/h3&gt;
&lt;p&gt;用于展示多条结构类似的数据，可对数据进行排序、筛选、对比或其他自定义操作。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-vue&#34;&gt;&amp;lt;template&amp;gt;
  &amp;lt;!-- :data=&amp;quot;tableData&amp;quot; 属性绑定表格中所有数据 
  slot-scope=&amp;quot;scope&amp;quot;  scope 存放的是表格中所有数据
  scope.row 获取该行数据
   width=&amp;quot;180&amp;quot; 调整列宽
  --&amp;gt;
    &amp;lt;el-table
      :data=&amp;quot;tableData&amp;quot;
      style=&amp;quot;width: 100%&amp;quot;&amp;gt;
      &amp;lt;el-table-column
        label=&amp;quot;日期&amp;quot;
        width=&amp;quot;200&amp;quot;&amp;gt;
        &amp;lt;template slot-scope=&amp;quot;scope&amp;quot;&amp;gt;
          &amp;lt;i class=&amp;quot;el-icon-time&amp;quot;&amp;gt;&amp;lt;/i&amp;gt;
          &amp;lt;span style=&amp;quot;margin-left: 10px&amp;quot;&amp;gt;&amp;#123;&amp;#123; scope.row.date &amp;#125;&amp;#125;&amp;lt;/span&amp;gt;
        &amp;lt;/template&amp;gt;
      &amp;lt;/el-table-column&amp;gt;
      &amp;lt;el-table-column
        label=&amp;quot;姓名&amp;quot;
        width=&amp;quot;180&amp;quot;&amp;gt;
        &amp;lt;template slot-scope=&amp;quot;scope&amp;quot;&amp;gt;
          &amp;lt;el-popover trigger=&amp;quot;hover&amp;quot; placement=&amp;quot;top&amp;quot;&amp;gt;
            &amp;lt;p&amp;gt;姓名: &amp;#123;&amp;#123; scope.row.name &amp;#125;&amp;#125;&amp;lt;/p&amp;gt;
            &amp;lt;p&amp;gt;住址: &amp;#123;&amp;#123; scope.row.address &amp;#125;&amp;#125;&amp;lt;/p&amp;gt;
            &amp;lt;div slot=&amp;quot;reference&amp;quot; class=&amp;quot;name-wrapper&amp;quot;&amp;gt;
              &amp;lt;el-tag size=&amp;quot;medium&amp;quot;&amp;gt;&amp;#123;&amp;#123; scope.row.name &amp;#125;&amp;#125;&amp;lt;/el-tag&amp;gt;
            &amp;lt;/div&amp;gt;
          &amp;lt;/el-popover&amp;gt;
        &amp;lt;/template&amp;gt;
      &amp;lt;/el-table-column&amp;gt;

      &amp;lt;el-table-column label=&amp;quot;操作&amp;quot; width=&amp;quot;200&amp;quot;  fixed=&amp;quot;right&amp;quot;&amp;gt;
        &amp;lt;template slot-scope=&amp;quot;scope&amp;quot;&amp;gt;
          &amp;lt;!-- scope.$index 获取行索引  scope.row 该行的数据--&amp;gt;
          &amp;lt;el-button
            size=&amp;quot;mini&amp;quot;
            @click=&amp;quot;handleEdit(scope.$index, scope.row)&amp;quot;&amp;gt;编辑&amp;lt;/el-button&amp;gt;
          &amp;lt;el-button
            size=&amp;quot;mini&amp;quot;
            type=&amp;quot;danger&amp;quot;
            @click=&amp;quot;handleDelete(scope.$index, scope.row)&amp;quot;&amp;gt;删除&amp;lt;/el-button&amp;gt;
        &amp;lt;/template&amp;gt;
      &amp;lt;/el-table-column&amp;gt;

    &amp;lt;/el-table&amp;gt;
  &amp;lt;/template&amp;gt;

&amp;lt;script&amp;gt;
  export default &amp;#123;
    data() &amp;#123;
      return &amp;#123;
        tableData: [&amp;#123;
          date: &#39;2016-05-02&#39;,
          name: &#39;王小虎&#39;,
          address: &#39;上海市普陀区金沙江路 1518 弄&#39;
        &amp;#125;, &amp;#123;
          date: &#39;2016-05-04&#39;,
          name: &#39;王小虎&#39;,
          address: &#39;上海市普陀区金沙江路 1517 弄&#39;
        &amp;#125;, &amp;#123;
          date: &#39;2016-05-01&#39;,
          name: &#39;王小虎&#39;,
          address: &#39;上海市普陀区金沙江路 1519 弄&#39;
        &amp;#125;, &amp;#123;
          date: &#39;2016-05-03&#39;,
          name: &#39;王小虎&#39;,
          address: &#39;上海市普陀区金沙江路 1516 弄&#39;
        &amp;#125;]
      &amp;#125;
    &amp;#125;,
    methods: &amp;#123;
      handleEdit(index, row) &amp;#123;
        console.log(index, row);
      &amp;#125;,
      handleDelete(index, row) &amp;#123;
        console.log(index, row);
      &amp;#125;
    &amp;#125;
  &amp;#125;
&amp;lt;/script&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;h3 id=&#34;12-pagination-分页&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#12-pagination-分页&#34;&gt;#&lt;/a&gt; 12. Pagination 分页&lt;/h3&gt;
&lt;p&gt;当数据量过多时，使用分页分解数据。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-vue&#34;&gt;&amp;lt;template&amp;gt;
  &amp;lt;!-- :data=&amp;quot;tableData&amp;quot; 属性绑定表格中所有数据 
  slot-scope=&amp;quot;scope&amp;quot;  scope 存放的是表格中所有数据
  scope.row 获取该行数据
   width=&amp;quot;180&amp;quot; 调整列宽
  --&amp;gt;
    &amp;lt;div&amp;gt;
      &amp;lt;el-table
      :data=&amp;quot;tableData&amp;quot;
      style=&amp;quot;width: 100%&amp;quot;&amp;gt;
      &amp;lt;el-table-column
        label=&amp;quot;日期&amp;quot;
        width=&amp;quot;200&amp;quot;&amp;gt;
        &amp;lt;template slot-scope=&amp;quot;scope&amp;quot;&amp;gt;
          &amp;lt;i class=&amp;quot;el-icon-time&amp;quot;&amp;gt;&amp;lt;/i&amp;gt;
          &amp;lt;span style=&amp;quot;margin-left: 10px&amp;quot;&amp;gt;&amp;#123;&amp;#123; scope.row.date &amp;#125;&amp;#125;&amp;lt;/span&amp;gt;
        &amp;lt;/template&amp;gt;
      &amp;lt;/el-table-column&amp;gt;
      &amp;lt;el-table-column
        label=&amp;quot;姓名&amp;quot;
        width=&amp;quot;180&amp;quot;&amp;gt;
        &amp;lt;template slot-scope=&amp;quot;scope&amp;quot;&amp;gt;
          &amp;lt;el-popover trigger=&amp;quot;hover&amp;quot; placement=&amp;quot;top&amp;quot;&amp;gt;
            &amp;lt;p&amp;gt;姓名: &amp;#123;&amp;#123; scope.row.name &amp;#125;&amp;#125;&amp;lt;/p&amp;gt;
            &amp;lt;p&amp;gt;住址: &amp;#123;&amp;#123; scope.row.address &amp;#125;&amp;#125;&amp;lt;/p&amp;gt;
            &amp;lt;div slot=&amp;quot;reference&amp;quot; class=&amp;quot;name-wrapper&amp;quot;&amp;gt;
              &amp;lt;el-tag size=&amp;quot;medium&amp;quot;&amp;gt;&amp;#123;&amp;#123; scope.row.name &amp;#125;&amp;#125;&amp;lt;/el-tag&amp;gt;
            &amp;lt;/div&amp;gt;
          &amp;lt;/el-popover&amp;gt;
        &amp;lt;/template&amp;gt;
      &amp;lt;/el-table-column&amp;gt;

      &amp;lt;el-table-column label=&amp;quot;操作&amp;quot; width=&amp;quot;200&amp;quot;  fixed=&amp;quot;right&amp;quot;&amp;gt;
        &amp;lt;template slot-scope=&amp;quot;scope&amp;quot;&amp;gt;
          &amp;lt;!-- scope.$index 获取行索引  scope.row 该行的数据--&amp;gt;
          &amp;lt;el-button
            size=&amp;quot;mini&amp;quot;
            @click=&amp;quot;handleEdit(scope.$index, scope.row)&amp;quot;&amp;gt;编辑&amp;lt;/el-button&amp;gt;
          &amp;lt;el-button
            size=&amp;quot;mini&amp;quot;
            type=&amp;quot;danger&amp;quot;
            @click=&amp;quot;handleDelete(scope.$index, scope.row)&amp;quot;&amp;gt;删除&amp;lt;/el-button&amp;gt;
        &amp;lt;/template&amp;gt;
      &amp;lt;/el-table-column&amp;gt;

    &amp;lt;/el-table&amp;gt;

    &amp;lt;div class=&amp;quot;block&amp;quot;&amp;gt;
      &amp;lt;span class=&amp;quot;demonstration&amp;quot;&amp;gt;完整功能&amp;lt;/span&amp;gt;
      &amp;lt;!-- 
        @size-change=&amp;quot;handleSizeChange&amp;quot;
        @current-change=&amp;quot;handleCurrentChange&amp;quot;
      :current-page=&amp;quot;currentPage4&amp;quot; 设置当前页的页码
      :page-sizes=&amp;quot;pageSize&amp;quot; 设置每页显示条数的选项
      :page-size=&amp;quot;100&amp;quot; 设置默认每页显示的条数
      layout=&amp;quot;total, sizes, prev, pager, next, jumper&amp;quot; 设置显示分页相关数据的顺序
      total 总条数 sizes 每页显示条数 prev 前一页 pager 页码 next 下一页jumper 跳转页
      --&amp;gt;
      &amp;lt;el-pagination
        @size-change=&amp;quot;handleSizeChange&amp;quot;
        @current-change=&amp;quot;handleCurrentChange&amp;quot;
        :current-page=&amp;quot;currentPage4&amp;quot;
        :page-sizes=&amp;quot;pageSize&amp;quot;
        :page-size=&amp;quot;20&amp;quot;
        layout=&amp;quot;total,sizes, prev, pager, next, jumper&amp;quot;
        :total=&amp;quot;total&amp;quot;&amp;gt;
      &amp;lt;/el-pagination&amp;gt;
    &amp;lt;/div&amp;gt;
    &amp;lt;/div&amp;gt;
  &amp;lt;/template&amp;gt;

&amp;lt;script&amp;gt;
  export default &amp;#123;
    data() &amp;#123;
      return &amp;#123;
        tableData: [&amp;#123;
          date: &#39;2016-05-02&#39;,
          name: &#39;王小虎&#39;,
          address: &#39;上海市普陀区金沙江路 1518 弄&#39;
        &amp;#125;, &amp;#123;
          date: &#39;2016-05-04&#39;,
          name: &#39;王小虎&#39;,
          address: &#39;上海市普陀区金沙江路 1517 弄&#39;
        &amp;#125;, &amp;#123;
          date: &#39;2016-05-01&#39;,
          name: &#39;王小虎&#39;,
          address: &#39;上海市普陀区金沙江路 1519 弄&#39;
        &amp;#125;, &amp;#123;
          date: &#39;2016-05-03&#39;,
          name: &#39;王小虎&#39;,
          address: &#39;上海市普陀区金沙江路 1516 弄&#39;
        &amp;#125;],
        // 每页显示的条数
        pageSize:[20, 100, 300, 400],
        total: 400, // 总条数
        currentPage4: 4 // 当前页
      &amp;#125;
    &amp;#125;,
    methods: &amp;#123;
      handleEdit(index, row) &amp;#123;
        console.log(index, row);
      &amp;#125;,
      handleDelete(index, row) &amp;#123;
        console.log(index, row);
      &amp;#125;,
      // 当每页显示的条数发生变化时触发的函数
      handleSizeChange(val) &amp;#123;
        console.log(`每页 $&amp;#123;val&amp;#125; 条`);
      &amp;#125;,
      // 当前页发生变化时触发的函数
      handleCurrentChange(val) &amp;#123;
        console.log(`当前页: $&amp;#123;val&amp;#125;`);
      &amp;#125;
    &amp;#125;
  &amp;#125;
&amp;lt;/script&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;h3 id=&#34;13message-消息提示和messagebox-弹框&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#13message-消息提示和messagebox-弹框&#34;&gt;#&lt;/a&gt; 13.Message 消息提示和 MessageBox 弹框&lt;/h3&gt;
&lt;pre&gt;&lt;code class=&#34;language-vue&#34;&gt;&amp;lt;template&amp;gt;
  &amp;lt;!-- :data=&amp;quot;tableData&amp;quot; 属性绑定表格中所有数据 
  slot-scope=&amp;quot;scope&amp;quot;  scope 存放的是表格中所有数据
  scope.row 获取该行数据
   width=&amp;quot;180&amp;quot; 调整列宽
  --&amp;gt;
    &amp;lt;div&amp;gt;
      &amp;lt;el-table
      :data=&amp;quot;tableData&amp;quot;
      style=&amp;quot;width: 100%&amp;quot;&amp;gt;
      &amp;lt;el-table-column
        label=&amp;quot;日期&amp;quot;
        width=&amp;quot;200&amp;quot;&amp;gt;
        &amp;lt;template slot-scope=&amp;quot;scope&amp;quot;&amp;gt;
          &amp;lt;i class=&amp;quot;el-icon-time&amp;quot;&amp;gt;&amp;lt;/i&amp;gt;
          &amp;lt;span style=&amp;quot;margin-left: 10px&amp;quot;&amp;gt;&amp;#123;&amp;#123; scope.row.date &amp;#125;&amp;#125;&amp;lt;/span&amp;gt;
        &amp;lt;/template&amp;gt;
      &amp;lt;/el-table-column&amp;gt;
      &amp;lt;el-table-column
        label=&amp;quot;姓名&amp;quot;
        width=&amp;quot;180&amp;quot;&amp;gt;
        &amp;lt;template slot-scope=&amp;quot;scope&amp;quot;&amp;gt;
          &amp;lt;el-popover trigger=&amp;quot;hover&amp;quot; placement=&amp;quot;top&amp;quot;&amp;gt;
            &amp;lt;p&amp;gt;姓名: &amp;#123;&amp;#123; scope.row.name &amp;#125;&amp;#125;&amp;lt;/p&amp;gt;
            &amp;lt;p&amp;gt;住址: &amp;#123;&amp;#123; scope.row.address &amp;#125;&amp;#125;&amp;lt;/p&amp;gt;
            &amp;lt;div slot=&amp;quot;reference&amp;quot; class=&amp;quot;name-wrapper&amp;quot;&amp;gt;
              &amp;lt;el-tag size=&amp;quot;medium&amp;quot;&amp;gt;&amp;#123;&amp;#123; scope.row.name &amp;#125;&amp;#125;&amp;lt;/el-tag&amp;gt;
            &amp;lt;/div&amp;gt;
          &amp;lt;/el-popover&amp;gt;
        &amp;lt;/template&amp;gt;
      &amp;lt;/el-table-column&amp;gt;

      &amp;lt;el-table-column label=&amp;quot;操作&amp;quot; width=&amp;quot;200&amp;quot;  fixed=&amp;quot;right&amp;quot;&amp;gt;
        &amp;lt;template slot-scope=&amp;quot;scope&amp;quot;&amp;gt;
          &amp;lt;!-- scope.$index 获取行索引  scope.row 该行的数据--&amp;gt;
          &amp;lt;el-button
            size=&amp;quot;mini&amp;quot;
            @click=&amp;quot;handleEdit(scope.$index, scope.row)&amp;quot;&amp;gt;编辑&amp;lt;/el-button&amp;gt;
          &amp;lt;el-button
            size=&amp;quot;mini&amp;quot;
            type=&amp;quot;danger&amp;quot;
            @click=&amp;quot;handleDelete(scope.$index, scope.row)&amp;quot;&amp;gt;删除&amp;lt;/el-button&amp;gt;
        &amp;lt;/template&amp;gt;
      &amp;lt;/el-table-column&amp;gt;

    &amp;lt;/el-table&amp;gt;

    &amp;lt;div class=&amp;quot;block&amp;quot;&amp;gt;
      &amp;lt;span class=&amp;quot;demonstration&amp;quot;&amp;gt;完整功能&amp;lt;/span&amp;gt;
      &amp;lt;!-- 
        @size-change=&amp;quot;handleSizeChange&amp;quot;
        @current-change=&amp;quot;handleCurrentChange&amp;quot;
      :current-page=&amp;quot;currentPage4&amp;quot; 设置当前页的页码
      :page-sizes=&amp;quot;pageSize&amp;quot; 设置每页显示条数的选项
      :page-size=&amp;quot;100&amp;quot; 设置默认每页显示的条数
      layout=&amp;quot;total, sizes, prev, pager, next, jumper&amp;quot; 设置显示分页相关数据的顺序
      total 总条数 sizes 每页显示条数 prev 前一页 pager 页码 next 下一页jumper 跳转页
      --&amp;gt;
      &amp;lt;el-pagination
        @size-change=&amp;quot;handleSizeChange&amp;quot;
        @current-change=&amp;quot;handleCurrentChange&amp;quot;
        :current-page=&amp;quot;currentPage4&amp;quot;
        :page-sizes=&amp;quot;pageSize&amp;quot;
        :page-size=&amp;quot;20&amp;quot;
        layout=&amp;quot;total,sizes, prev, pager, next, jumper&amp;quot;
        :total=&amp;quot;total&amp;quot;&amp;gt;
      &amp;lt;/el-pagination&amp;gt;
    &amp;lt;/div&amp;gt;

    &amp;lt;div&amp;gt;
      &amp;lt;el-button :plain=&amp;quot;true&amp;quot; @click=&amp;quot;open1&amp;quot;&amp;gt;消息&amp;lt;/el-button&amp;gt;
      &amp;lt;el-button :plain=&amp;quot;true&amp;quot; @click=&amp;quot;open2&amp;quot;&amp;gt;成功&amp;lt;/el-button&amp;gt;
      &amp;lt;el-button :plain=&amp;quot;true&amp;quot; @click=&amp;quot;open3&amp;quot;&amp;gt;警告&amp;lt;/el-button&amp;gt;
      &amp;lt;el-button :plain=&amp;quot;true&amp;quot; @click=&amp;quot;open4&amp;quot;&amp;gt;错误&amp;lt;/el-button&amp;gt;

      &amp;lt;el-button type=&amp;quot;danger&amp;quot; @click=&amp;quot;open&amp;quot;&amp;gt;删除&amp;lt;/el-button&amp;gt;
    &amp;lt;/div&amp;gt;

    &amp;lt;/div&amp;gt;
  &amp;lt;/template&amp;gt;

&amp;lt;script&amp;gt;
  export default &amp;#123;
    data() &amp;#123;
      return &amp;#123;
        tableData: [&amp;#123;
          date: &#39;2016-05-02&#39;,
          name: &#39;王小虎&#39;,
          address: &#39;上海市普陀区金沙江路 1518 弄&#39;
        &amp;#125;, &amp;#123;
          date: &#39;2016-05-04&#39;,
          name: &#39;王小虎&#39;,
          address: &#39;上海市普陀区金沙江路 1517 弄&#39;
        &amp;#125;, &amp;#123;
          date: &#39;2016-05-01&#39;,
          name: &#39;王小虎&#39;,
          address: &#39;上海市普陀区金沙江路 1519 弄&#39;
        &amp;#125;, &amp;#123;
          date: &#39;2016-05-03&#39;,
          name: &#39;王小虎&#39;,
          address: &#39;上海市普陀区金沙江路 1516 弄&#39;
        &amp;#125;],
        // 每页显示的条数
        pageSize:[20, 100, 300, 400],
        total: 400, // 总条数
        currentPage4: 4 // 当前页
      &amp;#125;
    &amp;#125;,
    methods: &amp;#123;
      open1()&amp;#123;
        this.$message(&amp;#123;
          showClose: true,
          message: &#39;这是一条消息提示&#39;
        &amp;#125;);
      &amp;#125;,
      open2()&amp;#123;
        this.$message.success(&amp;quot;成功了&amp;quot;);
      &amp;#125;,
      open3()&amp;#123;
        this.$message(&amp;#123;
          showClose: true,
          type: &amp;quot;warning&amp;quot;,
          message: &amp;quot;这是一个警告消息&amp;quot;
        &amp;#125;)
      &amp;#125;,
      open4()&amp;#123;
        this.$message.error(&amp;quot;这是一个错误信息&amp;quot;);
      &amp;#125;,
      open()&amp;#123;

        this.$confirm(&#39;是否确定删除?&#39;, &#39;提示&#39;, &amp;#123;
          confirmButtonText: &#39;确定&#39;,
          cancelButtonText: &#39;取消&#39;,
          type: &#39;warning&#39;
        &amp;#125;)
        .then(() =&amp;gt; &amp;#123;
          // 真实删除的逻辑
          this.$message(&amp;#123;
            type: &#39;success&#39;,
            message: &#39;删除成功!&#39;
          &amp;#125;);
        &amp;#125;).catch(() =&amp;gt; &amp;#123;
          this.$message(&amp;#123;
            type: &#39;info&#39;,
            message: &#39;已取消删除&#39;
          &amp;#125;);          
        &amp;#125;);
      &amp;#125;,
      handleEdit(index, row) &amp;#123;
        console.log(index, row);
      &amp;#125;,
      handleDelete(index, row) &amp;#123;
        console.log(index, row);
      &amp;#125;,
      // 当每页显示的条数发生变化时触发的函数
      handleSizeChange(val) &amp;#123;
        console.log(`每页 $&amp;#123;val&amp;#125; 条`);
      &amp;#125;,
      // 当前页发生变化时触发的函数
      handleCurrentChange(val) &amp;#123;
        console.log(`当前页: $&amp;#123;val&amp;#125;`);
      &amp;#125;
    &amp;#125;
  &amp;#125;
&amp;lt;/script&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;h3 id=&#34;14dialog-对话框&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#14dialog-对话框&#34;&gt;#&lt;/a&gt; 14.Dialog 对话框&lt;/h3&gt;
&lt;p&gt;在保留当前页面状态的情况下，告知用户并承载相关操作。&lt;/p&gt;
&lt;pre&gt;&lt;code class=&#34;language-vue&#34;&gt;&amp;lt;template&amp;gt;
  &amp;lt;div&amp;gt;
          &amp;lt;el-button type=&amp;quot;text&amp;quot; @click=&amp;quot;dialogFormVisible = true&amp;quot;&amp;gt;打开嵌套表单的 Dialog&amp;lt;/el-button&amp;gt;

      &amp;lt;el-dialog title=&amp;quot;收货地址&amp;quot; :visible.sync=&amp;quot;dialogFormVisible&amp;quot;&amp;gt;
        &amp;lt;el-form :model=&amp;quot;form&amp;quot;&amp;gt;
          &amp;lt;el-form-item label=&amp;quot;活动名称&amp;quot; :label-width=&amp;quot;formLabelWidth&amp;quot;&amp;gt;
            &amp;lt;el-input v-model=&amp;quot;form.name&amp;quot; autocomplete=&amp;quot;off&amp;quot;&amp;gt;&amp;lt;/el-input&amp;gt;
          &amp;lt;/el-form-item&amp;gt;
          &amp;lt;el-form-item label=&amp;quot;活动区域&amp;quot; :label-width=&amp;quot;formLabelWidth&amp;quot;&amp;gt;
            &amp;lt;el-select v-model=&amp;quot;form.region&amp;quot; placeholder=&amp;quot;请选择活动区域&amp;quot;&amp;gt;
              &amp;lt;el-option label=&amp;quot;区域一&amp;quot; value=&amp;quot;shanghai&amp;quot;&amp;gt;&amp;lt;/el-option&amp;gt;
              &amp;lt;el-option label=&amp;quot;区域二&amp;quot; value=&amp;quot;beijing&amp;quot;&amp;gt;&amp;lt;/el-option&amp;gt;
            &amp;lt;/el-select&amp;gt;
          &amp;lt;/el-form-item&amp;gt;
        &amp;lt;/el-form&amp;gt;
        &amp;lt;div slot=&amp;quot;footer&amp;quot; class=&amp;quot;dialog-footer&amp;quot;&amp;gt;
          &amp;lt;el-button @click=&amp;quot;dialogFormVisible = false&amp;quot;&amp;gt;取 消&amp;lt;/el-button&amp;gt;
          &amp;lt;el-button type=&amp;quot;primary&amp;quot; @click=&amp;quot;dialogFormVisible = false&amp;quot;&amp;gt;确 定&amp;lt;/el-button&amp;gt;
        &amp;lt;/div&amp;gt;
      &amp;lt;/el-dialog&amp;gt;


    &amp;lt;/div&amp;gt;

  &amp;lt;/template&amp;gt;

&amp;lt;script&amp;gt;
  export default &amp;#123;
    data() &amp;#123;
      return &amp;#123;
        dialogTableVisible: false,
        dialogFormVisible: false,
        form: &amp;#123;
          name: &#39;&#39;,
          region: &#39;&#39;,
          date1: &#39;&#39;,
          date2: &#39;&#39;,
          delivery: false,
          type: [],
          resource: &#39;&#39;,
          desc: &#39;&#39;
        &amp;#125;,
        formLabelWidth: &#39;120px&#39;
      &amp;#125;
    &amp;#125;,
  &amp;#125;
&amp;lt;/script&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;h3 id=&#34;ecmascript-6&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#ecmascript-6&#34;&gt;#&lt;/a&gt; ECMAScript 6&lt;/h3&gt;
&lt;h4 id=&#34;1-简介&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1-简介&#34;&gt;#&lt;/a&gt; 1. 简介&lt;/h4&gt;
&lt;blockquote&gt;
&lt;p&gt;​	ECMAScript 6.0（以下简称 ES6）是 JavaScript 语言的下一代标准，已经在 2015 年 6 月正式发布了。它的目标，是使得 JavaScript 语言可以用来编写复杂的大型应用程序，成为企业级开发语言。&lt;/p&gt;
&lt;p&gt;优点:&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;提升了 Js 编写复杂大型应用程序的能力；(这次提升，主要加入了模块化的概念，优化了一些基础语法，封装了一些方法，使得 JS 更可用于大型模块化项目的开发)&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;缺点:&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;和一些浏览器还存在兼容性问题，解决办法：Bable 插件 (将 ES6-&amp;gt;ES5) 转换器&lt;/li&gt;
&lt;/ul&gt;
&lt;/blockquote&gt;
&lt;h4 id=&#34;2-基本语法&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2-基本语法&#34;&gt;#&lt;/a&gt; 2. 基本语法&lt;/h4&gt;
&lt;p&gt;ES 标准中不包含 DOM 和 BOM 的定义，只涵盖基本数据类型、关键字、语句、运算符、内建对象、内建函数等通用语法。&lt;/p&gt;
&lt;h5 id=&#34;1let声明变量&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1let声明变量&#34;&gt;#&lt;/a&gt; 1）let 声明变量&lt;/h5&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;块级作用域:&lt;/p&gt;
&lt;p&gt;&lt;code&gt;let&lt;/code&gt;  实际上为 JavaScript 新增了块级作用域。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;不允许重复声明&lt;/p&gt;
&lt;p&gt;&lt;code&gt;let&lt;/code&gt;  不允许在相同作用域内，重复声明同一个变量。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;不存在变量提升&lt;/p&gt;
&lt;p&gt;&lt;code&gt;var&lt;/code&gt;  命令会发生” 变量提升 “现象，即变量可以在声明之前使用，值为 &lt;code&gt;undefined&lt;/code&gt; 。这种现象多多少少是有些奇怪的，按照一般的逻辑，变量应该在声明语句之后才可以使用。&lt;/p&gt;
&lt;p&gt;为了纠正这种现象， &lt;code&gt;let&lt;/code&gt;  命令改变了语法行为，它所声明的变量一定要在声明后使用，否则报错。&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h5 id=&#34;2const声明常量&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2const声明常量&#34;&gt;#&lt;/a&gt; 2）const 声明常量&lt;/h5&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;&lt;code&gt;const&lt;/code&gt;  声明一个只读的常量。一旦声明，常量的值就不能改变。&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;一但声明必须初始化，否则会报错&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;figure class=&#34;highlight js&#34;&gt;&lt;figcaption data-lang=&#34;JavaScript&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;script&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token comment&#34;&gt;// ES6 之前所有变量都用 var 声明&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;var&lt;/span&gt; num &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;10&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        console&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;log&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;num&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token keyword&#34;&gt;var&lt;/span&gt; a &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;20&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token comment&#34;&gt;//1. let 声明的变量只能在他所在的大括号中访问&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; c &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;100&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            console&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;log&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;var： &#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;a&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            console&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;log&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;let &#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;c&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                console&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;log&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;括号内&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;a&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;c&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;16&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;17&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        console&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;log&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;var1： &#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;a&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;18&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;       &lt;span class=&#34;token comment&#34;&gt;// console.log(&#34;let1 &#34;,c);&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;19&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;var&lt;/span&gt; g &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;66&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;20&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;var&lt;/span&gt; g &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;88&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;21&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        console&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;log&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;g&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;g&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;22&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; f &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;33&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;23&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token comment&#34;&gt;//2. let 不允许重复声明&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;24&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token comment&#34;&gt;//let f = 99;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;25&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        console&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;log&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;f&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;26&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;27&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        console&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;log&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;sum&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;28&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;var&lt;/span&gt; sum &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;55&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;29&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token comment&#34;&gt;// 不存在变量提升，let 变量需要先定义再使用&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;30&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token comment&#34;&gt;// Cannot access &#39;su&#39; before initialization&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;31&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token comment&#34;&gt;// console.log(su);&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;32&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; su &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;44&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;33&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;34&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;/&lt;/span&gt;script&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;35&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;36&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;script&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;37&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token comment&#34;&gt;// 1. 定义后常量必须初始化&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;38&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;const&lt;/span&gt; &lt;span class=&#34;token constant&#34;&gt;PI&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;3.14&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;39&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token comment&#34;&gt;// 2. 常量一旦赋值就不可以改变&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;40&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token comment&#34;&gt;// Assignment to constant variable.&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;41&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;       &lt;span class=&#34;token comment&#34;&gt;// PI = 55;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;42&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        console&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;log&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token constant&#34;&gt;PI&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;43&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;/&lt;/span&gt;script&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h5 id=&#34;3解构赋值&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#3解构赋值&#34;&gt;#&lt;/a&gt; 3）解构赋值&lt;/h5&gt;
&lt;p&gt;ES6 允许按照一定模式，从数组和对象中提取值，对变量进行赋值，这被称为解构（Destructuring）。&lt;/p&gt;
&lt;p&gt;解构赋值是对赋值运算符的扩展。&lt;br /&gt;
他是一种针对数组或者对象进行模式匹配，然后对其中的变量进行赋值。&lt;br /&gt;
在代码书写上简洁且易读，语义更加清晰明了；也方便了复杂对象中数据字段获取。&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;数组的结构赋值&lt;/p&gt;
&lt;figure class=&#34;highlight js&#34;&gt;&lt;figcaption data-lang=&#34;JavaScript&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;script&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; arr &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;12&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;34&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;66&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt; &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token comment&#34;&gt;// 将数组中的三个元素赋值给 x,y，z 三个变量&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token comment&#34;&gt;// 传统写法&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; a &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; arr&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;       &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; b &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; arr&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;       &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; c &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; arr&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;2&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        console&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;log&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;a&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;b&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;c&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt; &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token comment&#34;&gt;// 解构赋值&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;x&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;y&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;z&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; arr&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        console&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;log&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;x&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;y&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;z&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;      &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;/&lt;/span&gt;script&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/li&gt;
&lt;li&gt;
&lt;h5 id=&#34;对象的解构赋值&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#对象的解构赋值&#34;&gt;#&lt;/a&gt; 对象的解构赋值&lt;/h5&gt;
&lt;figure class=&#34;highlight js&#34;&gt;&lt;figcaption data-lang=&#34;JavaScript&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;script&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; user &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;span class=&#34;token literal-property property&#34;&gt;name&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;张三&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token literal-property property&#34;&gt;age&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;12&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token literal-property property&#34;&gt;gender&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;woman&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token comment&#34;&gt;// 将对象的属性赋值给三个变量&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token comment&#34;&gt;// es5  &lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; na &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; user&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;name&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; age &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; user&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;age&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; sex &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; user&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;gender&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        console&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;log&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;na&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;age&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;sex&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token comment&#34;&gt;// ES 6 解构赋值，等号左边匹配值时， 从左向右， 先匹配属性名，然后将右边的属性值给右边的变量名&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token comment&#34;&gt;// 如果变量名和属性名不一致， 将变量名写在冒号的右侧， 如果一致， 可以省略不写&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;span class=&#34;token literal-property property&#34;&gt;name&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt;aaa&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token literal-property property&#34;&gt;age&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt;ag&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;gender&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; user&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        console&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;log&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;aaa&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;ag&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;gender&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;/&lt;/span&gt;script&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;h5 id=&#34;4模板字符串&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#4模板字符串&#34;&gt;#&lt;/a&gt; 4）模板字符串&lt;/h5&gt;
&lt;p&gt;​	模板字符串相当于加强版的字符串，用反引号 `, 除了作为普通字符串，还可以用来定义多行字符串，还可以在字符串中加入变量和表达式。&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;多行字符串&lt;/li&gt;
&lt;li&gt;字符串插入变量和表达式。变量名写在 &lt;code&gt; $&amp;#123;&amp;#125;&lt;/code&gt;  中， &lt;code&gt;$&amp;#123;&amp;#125; &lt;/code&gt; 中可以放入 JavaScript 表达式。&lt;/li&gt;
&lt;li&gt;字符串中调用函数&lt;/li&gt;
&lt;/ol&gt;
&lt;figure class=&#34;highlight js&#34;&gt;&lt;figcaption data-lang=&#34;JavaScript&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;script&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;var&lt;/span&gt; st &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;&amp;lt;div&gt;&#34;&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token string&#34;&gt;&#34;&amp;lt;p&gt;这是一个段落&amp;lt;/p&gt;&#34;&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt; &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token string&#34;&gt;&#34;&amp;lt;/div&gt;&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token comment&#34;&gt;// 模板字符串可以换行可以保留空格和 table 以及换行符等&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;var&lt;/span&gt; st1 &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token template-string&#34;&gt;&lt;span class=&#34;token template-punctuation string&#34;&gt;`&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&amp;lt;div&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                    &amp;lt;a href=&#34;&#34;&gt;a标签&amp;lt;/a&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                &amp;lt;/div&gt;&lt;/span&gt;&lt;span class=&#34;token template-punctuation string&#34;&gt;`&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;  &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        console&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;log&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;st&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;        &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        console&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;log&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;st1&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;   &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;var&lt;/span&gt; user &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;span class=&#34;token literal-property property&#34;&gt;name&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;林蛋大&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token literal-property property&#34;&gt;age&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;22&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;var&lt;/span&gt; desc &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;我是&#34;&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt; user&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;name &lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;今年&#34;&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt; user&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;age &lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;岁&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;16&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token comment&#34;&gt;// 模板字符串使用变量&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;17&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; des &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token template-string&#34;&gt;&lt;span class=&#34;token template-punctuation string&#34;&gt;`&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;我是&lt;/span&gt;&lt;span class=&#34;token interpolation&#34;&gt;&lt;span class=&#34;token interpolation-punctuation punctuation&#34;&